export function translateKey(
  key: string,
  language: LanguageCode | string | null | undefined,
  fallback?: string
) {
  const normalizedLanguage = normalizeLanguage(language);
  const direct = APP_TRANSLATIONS[normalizedLanguage]?.[key] || APP_TRANSLATIONS.it[key];
  if (direct) return direct;

  if (fallback) {
    return translateKnownText(fallback, normalizedLanguage);
  }

  if (key.startsWith("ui.")) {
    return translateKnownText(key.slice(3), normalizedLanguage);
  }

  return humanizeMissingTranslationKey(key);
}

function humanizeMissingTranslationKey(key: string) {
  const lastSegment = String(key || "").split(".").filter(Boolean).pop() || key;
  return lastSegment
    .replace(/[_-]+/g, " ")
    .replace(/([a-zà-ÿ])([A-Z])/g, "$1 $2")
    .trim() || key;
}

