const IT_CONNECTOR_SORTED = IT_CONNECTOR_WORDS.slice().sort((a, b) => b.it.length - a.it.length);

function replaceConnectorWords(value: string, targetLanguage: LanguageCode) {
  if (targetLanguage === "it") return value;

  let result = value;
  for (const entry of IT_CONNECTOR_SORTED) {
    const source = entry.it;
    const target = entry[targetLanguage];
    const escaped = escapeRegExp(source);
    const pattern = new RegExp(`(^|[^\p{L}\p{N}])(${escaped})(?=$|[^\p{L}\p{N}])`, "giu");
    result = result.replace(pattern, (_match, prefix) => `${prefix}${target}`);
  }
  return result;
}

function translateCompositeText(value: string, targetLanguage: LanguageCode) {
  let result = translateByGlossary(value, targetLanguage);
  const glossaryChanged = result !== value;

  if (targetLanguage !== "it") {
    result = result
      .replace(/\bcorrettamente\b/gi, targetLanguage === "en" ? "successfully" : targetLanguage === "fr" ? "correctement" : targetLanguage === "es" ? "correctamente" : "erfolgreich")
      .replace(/\baggiornato\b/gi, targetLanguage === "en" ? "updated" : targetLanguage === "fr" ? "mis à jour" : targetLanguage === "es" ? "actualizado" : "aktualisiert")
      .replace(/\baggiornata\b/gi, targetLanguage === "en" ? "updated" : targetLanguage === "fr" ? "mise à jour" : targetLanguage === "es" ? "actualizada" : "aktualisiert")
      .replace(/\bcreato\b/gi, targetLanguage === "en" ? "created" : targetLanguage === "fr" ? "créé" : targetLanguage === "es" ? "creado" : "erstellt")
      .replace(/\bcreata\b/gi, targetLanguage === "en" ? "created" : targetLanguage === "fr" ? "créée" : targetLanguage === "es" ? "creada" : "erstellt")
      .replace(/\bsalvato\b/gi, targetLanguage === "en" ? "saved" : targetLanguage === "fr" ? "enregistré" : targetLanguage === "es" ? "guardado" : "gespeichert")
      .replace(/\bsalvata\b/gi, targetLanguage === "en" ? "saved" : targetLanguage === "fr" ? "enregistrée" : targetLanguage === "es" ? "guardada" : "gespeichert")
      .replace(/\beliminato\b/gi, targetLanguage === "en" ? "deleted" : targetLanguage === "fr" ? "supprimé" : targetLanguage === "es" ? "eliminado" : "gelöscht")
      .replace(/\beliminata\b/gi, targetLanguage === "en" ? "deleted" : targetLanguage === "fr" ? "supprimée" : targetLanguage === "es" ? "eliminada" : "gelöscht")
      .replace(/\bnon trovato\b/gi, targetLanguage === "en" ? "not found" : targetLanguage === "fr" ? "introuvable" : targetLanguage === "es" ? "no encontrado" : "nicht gefunden")
      .replace(/\bnon trovata\b/gi, targetLanguage === "en" ? "not found" : targetLanguage === "fr" ? "introuvable" : targetLanguage === "es" ? "no encontrada" : "nicht gefunden")
      .replace(/\bin corso\b/gi, targetLanguage === "en" ? "in progress" : targetLanguage === "fr" ? "en cours" : targetLanguage === "es" ? "en curso" : "in Bearbeitung");
  }

  if (glossaryChanged) {
    result = replaceConnectorWords(result, targetLanguage);
  }

  return result;
}

export function translateKnownText(value: string, language: LanguageCode | string | null | undefined) {
  const targetLanguage = normalizeLanguage(language);
  const trimmed = value.trim();
  if (!trimmed) return value;

  const exact = findLegacyText(trimmed) || findFallbackGlossaryText(trimmed);
  if (exact) {
    return preserveOuterWhitespace(value, exact[targetLanguage]);
  }

  const rolePrefixes = [
    texts("Ruolo", "Role", "Rôle", "Rol", "Rolle"),
  ];

  for (const prefix of rolePrefixes) {
    for (const sourceLanguage of SUPPORTED_LANGUAGES) {
      const sourcePrefix = prefix[sourceLanguage.code];
      if (trimmed.startsWith(`${sourcePrefix}:`)) {
        return preserveOuterWhitespace(
          value,
          `${prefix[targetLanguage]}: ${trimmed.slice(sourcePrefix.length + 1).trim()}`
        );
      }
    }
  }

  // Importante: non traduciamo più frasi parziali/parola per parola.
  // La precedente logica a glossario era troppo aggressiva e poteva generare testi
  // lunghi o innaturali che rompevano card, badge e intestazioni.
  return value;
}

export function translateElementAttributes(_root: ParentNode, _language: LanguageCode) {
  // Safe mode: no DOM-wide translation.
  // Translating arbitrary DOM attributes after render is expensive on large pages
  // (inventory tables, telemetry lists, virtualized content) and can also touch
  // user/database data. Static UI text must be translated at render time with t().
  return;
}

export function translateDocumentText(language: LanguageCode | string | null | undefined) {
  // Safe mode: keep only the document language metadata.
  // Do not walk document.body and do not mutate text nodes/attributes after render.
  if (typeof document === "undefined") return;

  const targetLanguage = normalizeLanguage(language);
  document.documentElement.lang = targetLanguage;
  document.documentElement.dataset.language = targetLanguage;
}
